            a[i, edge] = 1
            d_isqrt[i, i] = 1 / math.sqrt(len(node))
    eye = torch.eye(h * w)
    lap = eye - d_isqrt @ a @ d_isqrt
    vals, vecs = torch.linalg.eigh(lap)
